import React from 'react'
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import HeroImg2 from '../components/HeroImg2';
const About = () => {
  return <div>
      <Navbar/>
      <HeroImg2 heading="About." text="I'm a Junior Full Stack Developer who loves creative problem solving and is passionate about emerging technologies. I'm a very fast learner who is looking for my first job as a developer.
      Experienced with: JavaScript, React.js, Node.js, MongoDB, Python, HTML, CSS, APIs, JSON, UI/UX ,Bootstrap"/>
      <Footer/>
      </div>
  
}

export default About
